import React from "react";
import { BrowserRouter as Router, Route, Routes, Link } from "react-router-dom";
import PersonasTable from "./PersonasTable";
import Horario from "./Horario"; // Asegúrate de que tienes este componente creado
import MateriasMatriculadas from "./MateriasMatriculadas"; // Importa el nuevo componente

function App() {
  return (
    <Router>
      <div className="App">
        <nav>
          <ul>
            <li>
              <Link to="/">Personas Registradas</Link>
            </li>
            <li>
              <Link to="/horario">Horario</Link>
            </li>
          </ul>
        </nav>

        <Routes>
          <Route path="/" element={<PersonasTable />} />
          <Route path="/horario" element={<Horario />} />{" "}
          {/* Ruta para el componente Horario */}
          <Route path="/MateriasMatriculadas" element={<MateriasMatriculadas />} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
